#include<bits/stdc++.h>
using namespace std;
int t[1000010],w[1000010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&t[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&w[i]);
    }
    for(int i=n-1;i>=1;i--)
    {
        t[i]=min(t[i],t[i+1]);
    }
    long long sum=0;
    long long ans=0;
    for(int i=n;i>=1;i--)
    {
        sum+=w[i];
        if(sum>0)
        {
            ans+=sum*t[i];
            sum=0;
        }
    }
    printf("%lld",ans);
    return 0;
}
